import os
from datetime import datetime, timedelta, timezone

from flask import Flask, jsonify, request
from jwt import encode, decode, exceptions

class JWTAuth:
    def __init__(self, app=None, secret_key=None):
        self.secret_key = secret_key
        if app is not None:
            self.init_app(app)

    def init_app(self, app):
        if self.secret_key is None:
            self.secret_key = app.config.get('JWT_SECRET_KEY')
            if self.secret_key is None:
                raise ValueError("JWT_SECRET_KEY must be set in app config or passed to JWTAuth")
        app.extensions['jwt_auth'] = self
        self.app = app

    def create_token(self, user_identity, expires_delta=None):
        if expires_delta is None:
            expires_delta = timedelta(hours=1) # Default expiration

        now = datetime.now(timezone.utc)
        expires = now + expires_delta

        payload = {
            'sub': user_identity,
            'iat': now,
            'exp': expires
        }
        return encode(payload, self.secret_key, algorithm='HS256')

    def verify_token(self, token):
        try:
            payload = decode(token, self.secret_key, algorithms=['HS256'])
            return payload['sub']
        except exceptions.ExpiredSignatureError:
            return None # Token has expired
        except exceptions.InvalidTokenError:
            return None # Invalid token (e.g., tampered, wrong signature)

    def login_required(self, f):
        def wrapper(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            if not auth_header:
                return jsonify({'message': 'Authorization header is missing'}), 401

            try:
                token_type, token = auth_header.split(None, 1)
            except ValueError:
                return jsonify({'message': 'Invalid Authorization header format'}), 401

            if token_type.lower() != 'bearer':
                return jsonify({'message': 'Unsupported authorization type'}), 401

            current_user = self.verify_token(token)
            if current_user is None:
                return jsonify({'message': 'Invalid or expired token'}), 401

            # Store current_user in Flask's g object for easy access in views
            from flask import g
            g.current_user = current_user
            return f(*args, **kwargs)
        wrapper.__name__ = f.__name__ # Preserve original function name for Flask
        return wrapper

if __name__ == '__main__':
    app = Flask(__name__)
    app.config['JWT_SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY', 'super-secret-key-please-change-me')

    jwt_auth = JWTAuth(app)

    # In a real application, you would fetch user from a database
