    users_db = {
        'john_doe': {'password': 'password123'},
        'jane_doe': {'password': 'securepwd'}
    }

    @app.route('/')
    def index():
        return jsonify({'message': 'Welcome to the Flask JWT API example!'})

    @app.route('/login', methods=['POST'])
    def login():
        username = request.json.get('username', None)
        password = request.json.get('password', None)

        if not username or not password:
            return jsonify({'message': 'Missing username or password'}), 400

        user = users_db.get(username)
        if user and user['password'] == password: # In real app: check hashed password
            access_token = jwt_auth.create_token(username)
            return jsonify(access_token=access_token), 200
        else:
            return jsonify({'message': 'Invalid credentials'}), 401

    @app.route('/protected', methods=['GET'])
    @jwt_auth.login_required
    def protected_route():
        from flask import g
        return jsonify({'message': f'Hello, {g.current_user}! You accessed a protected resource.'}), 200

